  ('e_0797', 'p_g11', 'support@example.com', 'Follow-up on Tuesday''s outage — RCA needed', '<p>We got hit by Tuesday''s 23-minute outage and lost about 4,000 inbound messages from a partner integration. Need a full RCA and a plan to prevent recurrence before our next exec review.</p>', 'We got hit by Tuesday''s 23-minute outage and lost about 4,000 inbound messages from a partner integration. Need a full RCA and a plan to prevent recurrence before our next exec review.', '{}', '<e_0797@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 463436), (CAST(strftime('%s','now') AS INTEGER) - 463436), '[{"email":"irina.popov@northwind.co","name":"Irina Popov"},{"email":"mateo.santos@northwind.co","name":"Mateo Santos"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_244601dab22d17a1'),
  ('e_0798', 'p_g12', 'support@example.com', 'Re: Follow-up on Tuesday''s outage — RCA needed', '<p>Thanks. Adding Mateo from our partner engineering team — he''ll be the technical contact for the replay.</p>', 'Thanks. Adding Mateo from our partner engineering team — he''ll be the technical contact for the replay.', '{}', '<e_0798@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 460655), (CAST(strftime('%s','now') AS INTEGER) - 460655), '[{"email":"alec.briggs@northwind.co","name":"Alec Briggs"},{"email":"mateo.santos@northwind.co","name":"Mateo Santos"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_244601dab22d17a1'),
  ('e_0799', 'p_g13', 'support@example.com', 'Re: Follow-up on Tuesday''s outage — RCA needed', '<p>Confirmed receipt of the 3,841. For the 159 — can you share which sender domains they came from? We can cross-reference against our partner logs.</p>', 'Confirmed receipt of the 3,841. For the 159 — can you share which sender domains they came from? We can cross-reference against our partner logs.', '{}', '<e_0799@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 415080), (CAST(strftime('%s','now') AS INTEGER) - 415080), '[{"email":"alec.briggs@northwind.co","name":"Alec Briggs"},{"email":"irina.popov@northwind.co","name":"Irina Popov"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_244601dab22d17a1');

INSERT OR REPLACE INTO emails (id, person_id, recipient, subject, body_html, body_text, raw_headers, message_id, spf, dkim, dmarc, is_read, received_at, created_at, cc, conversation_id) VALUES
  ('e_0800', 'p_g11', 'support@example.com', 'Re: Follow-up on Tuesday''s outage — RCA needed', '<p>RCA looks thorough. Approving the incident as resolved on our side. Will share the summary with our exec team.</p>', 'RCA looks thorough. Approving the incident as resolved on our side. Will share the summary with our exec team.', '{}', '<e_0800@example.test>', 'pass', 'pass', 'pass', 0, (CAST(strftime('%s','now') AS INTEGER) - 222265), (CAST(strftime('%s','now') AS INTEGER) - 222265), '[{"email":"irina.popov@northwind.co","name":"Irina Popov"},{"email":"mateo.santos@northwind.co","name":"Mateo Santos"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_244601dab22d17a1'),
  ('e_0801', 'p_g14', 'hello@example.com', 'Stark onboarding — kickoff next steps', '<p>Excited to get started. Looping in Ravi (engineering lead) and Lucia (ops). Can we schedule a kickoff next week and get the migration runbook?</p>', 'Excited to get started. Looping in Ravi (engineering lead) and Lucia (ops). Can we schedule a kickoff next week and get the migration runbook?', '{}', '<e_0801@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1009635), (CAST(strftime('%s','now') AS INTEGER) - 1009635), '[{"email":"ravi.menon@stark.industries","name":"Ravi Menon"},{"email":"lucia.fernandez@stark.industries","name":"Lucia Fernandez"},{"email":"maya@example.com","name":"Maya Iyer"}]', 'c_7b2fe860ab89bc71'),
  ('e_0802', 'p_g15', 'hello@example.com', 'Re: Stark onboarding — kickoff next steps', '<p>Quick technical question — does the runbook assume single-region or are you moving us to the multi-region setup from day one?</p>', 'Quick technical question — does the runbook assume single-region or are you moving us to the multi-region setup from day one?', '{}', '<e_0802@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 866177), (CAST(strftime('%s','now') AS INTEGER) - 866177), '[{"email":"jana.kowalski@stark.industries","name":"Jana Kowalski"},{"email":"lucia.fernandez@stark.industries","name":"Lucia Fernandez"},{"email":"maya@example.com","name":"Maya Iyer"}]', 'c_7b2fe860ab89bc71'),
  ('e_0803', 'p_g16', 'hello@example.com', 'Re: Stark onboarding — kickoff next steps', '<p>From the ops side: who owns DNS during the cutover? We can either do it ourselves or hand off — depends on your usual process.</p>', 'From the ops side: who owns DNS during the cutover? We can either do it ourselves or hand off — depends on your usual process.', '{}', '<e_0803@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 798623), (CAST(strftime('%s','now') AS INTEGER) - 798623), '[{"email":"jana.kowalski@stark.industries","name":"Jana Kowalski"},{"email":"ravi.menon@stark.industries","name":"Ravi Menon"},{"email":"maya@example.com","name":"Maya Iyer"}]', 'c_7b2fe860ab89bc71'),
  ('e_0804', 'p_g14', 'hello@example.com', 'Re: Stark onboarding — kickoff next steps', '<p>Let''s keep DNS on our side. See you Tuesday.</p>', 'Let''s keep DNS on our side. See you Tuesday.', '{}', '<e_0804@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 749280), (CAST(strftime('%s','now') AS INTEGER) - 749280), '[{"email":"ravi.menon@stark.industries","name":"Ravi Menon"},{"email":"lucia.fernandez@stark.industries","name":"Lucia Fernandez"},{"email":"maya@example.com","name":"Maya Iyer"}]', 'c_7b2fe860ab89bc71'),
  ('e_0805', 'p_g17', 'support@example.com', 'Chat-mode UI for support inboxes — feedback', '<p>We''ve been on the chat-mode beta for a week and have collated feedback from our 14-person support team. Top three asks: keyboard-only navigation, per-conversation sound toggles, and a way to surface roster changes more clearly.</p>', 'We''ve been on the chat-mode beta for a week and have collated feedback from our 14-person support team. Top three asks: keyboard-only navigation, per-conversation sound toggles, and a way to surface roster changes more clearly.', '{}', '<e_0805@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1398774), (CAST(strftime('%s','now') AS INTEGER) - 1398774), '[{"email":"hugo.lefevre@umbrella.med","name":"Hugo Lefevre"},{"email":"anika.osei@umbrella.med","name":"Anika Osei"},{"email":"petr.zelinka@umbrella.med","name":"Petr Zelinka"},{"email":"lin@example.com","name":"Lin Park"},{"email":"diego@example.com","name":"Diego Cruz"}]', 'c_1a81a93e429517f7'),
  ('e_0806', 'p_g18', 'support@example.com', 'Re: Chat-mode UI for support inboxes — feedback', '<p>Adding to that — the avatar overlap at 5+ participants gets visually noisy. We''d love an option to collapse to ''X others'' after the first three.</p>', 'Adding to that — the avatar overlap at 5+ participants gets visually noisy. We''d love an option to collapse to ''X others'' after the first three.', '{}', '<e_0806@example.test>', 'pass', 'pass', 'pass', 0, (CAST(strftime('%s','now') AS INTEGER) - 1423084), (CAST(strftime('%s','now') AS INTEGER) - 1423084), '[{"email":"deepa.rao@umbrella.med","name":"Deepa Rao"},{"email":"anika.osei@umbrella.med","name":"Anika Osei"},{"email":"petr.zelinka@umbrella.med","name":"Petr Zelinka"},{"email":"lin@example.com","name":"Lin Park"},{"email":"diego@example.com","name":"Diego Cruz"}]', 'c_1a81a93e429517f7'),
  ('e_0807', 'p_g19', 'support@example.com', 'Re: Chat-mode UI for support inboxes — feedback', '<p>Anika here, design lead. Curious what the roster-change UI looks like — is it a banner, a chip, or inline text? Happy to share our redlines if you want a second opinion.</p>', 'Anika here, design lead. Curious what the roster-change UI looks like — is it a banner, a chip, or inline text? Happy to share our redlines if you want a second opinion.', '{}', '<e_0807@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1308352), (CAST(strftime('%s','now') AS INTEGER) - 1308352), '[{"email":"deepa.rao@umbrella.med","name":"Deepa Rao"},{"email":"hugo.lefevre@umbrella.med","name":"Hugo Lefevre"},{"email":"petr.zelinka@umbrella.med","name":"Petr Zelinka"},{"email":"lin@example.com","name":"Lin Park"},{"email":"diego@example.com","name":"Diego Cruz"}]', 'c_1a81a93e429517f7'),
  ('e_0808', 'p_g20', 'support@example.com', 'Re: Chat-mode UI for support inboxes — feedback', '<p>Petr from engineering — when keyboard nav ships, can we get the keymap configurable? Half my team is on Vim bindings, half on default.</p>', 'Petr from engineering — when keyboard nav ships, can we get the keymap configurable? Half my team is on Vim bindings, half on default.', '{}', '<e_0808@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1151689), (CAST(strftime('%s','now') AS INTEGER) - 1151689), '[{"email":"deepa.rao@umbrella.med","name":"Deepa Rao"},{"email":"hugo.lefevre@umbrella.med","name":"Hugo Lefevre"},{"email":"anika.osei@umbrella.med","name":"Anika Osei"},{"email":"lin@example.com","name":"Lin Park"},{"email":"diego@example.com","name":"Diego Cruz"}]', 'c_1a81a93e429517f7'),
  ('e_0809', 'p_g19', 'support@example.com', 'Re: Chat-mode UI for support inboxes — feedback', '<p>Saw the Loom. The pill placement is great. One nit: the icon for ''left'' reads a little aggressive — we''d suggest a softer chevron-out instead of an X.</p>', 'Saw the Loom. The pill placement is great. One nit: the icon for ''left'' reads a little aggressive — we''d suggest a softer chevron-out instead of an X.', '{}', '<e_0809@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1116581), (CAST(strftime('%s','now') AS INTEGER) - 1116581), '[{"email":"deepa.rao@umbrella.med","name":"Deepa Rao"},{"email":"hugo.lefevre@umbrella.med","name":"Hugo Lefevre"},{"email":"petr.zelinka@umbrella.med","name":"Petr Zelinka"},{"email":"lin@example.com","name":"Lin Park"},{"email":"diego@example.com","name":"Diego Cruz"}]', 'c_1a81a93e429517f7'),
  ('e_0810', 'p_g17', 'support@example.com', 'Re: Chat-mode UI for support inboxes — feedback', '<p>Thanks all. We''ll keep funneling feedback as we expand the rollout to more reps.</p>', 'Thanks all. We''ll keep funneling feedback as we expand the rollout to more reps.', '{}', '<e_0810@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 839297), (CAST(strftime('%s','now') AS INTEGER) - 839297), '[{"email":"hugo.lefevre@umbrella.med","name":"Hugo Lefevre"},{"email":"anika.osei@umbrella.med","name":"Anika Osei"},{"email":"petr.zelinka@umbrella.med","name":"Petr Zelinka"},{"email":"lin@example.com","name":"Lin Park"},{"email":"diego@example.com","name":"Diego Cruz"}]', 'c_1a81a93e429517f7'),
  ('e_0811', 'p_g09', 'sales@example.com', 'RFP response — Globex / Acme joint deployment', '<p>Joint RFP for the Globex/Acme deployment. We''re evaluating three vendors. Tariq from Acme legal is leading the contract review side; Olu is the technical evaluator on Globex''s end.</p>', 'Joint RFP for the Globex/Acme deployment. We''re evaluating three vendors. Tariq from Acme legal is leading the contract review side; Olu is the technical evaluator on Globex''s end.', '{}', '<e_0811@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1870343), (CAST(strftime('%s','now') AS INTEGER) - 1870343), '[{"email":"olu.adebayo@globex.io","name":"Olu Adebayo"},{"email":"tariq.khan@legal.acme.co","name":"Tariq Khan"},{"email":"pavel@example.com","name":"Pavel Novak"}]', 'c_eb8f309dcca13e8a'),
  ('e_0812', 'p_g21', 'sales@example.com', 'Re: RFP response — Globex / Acme joint deployment', '<p>Section 4 (architecture) and section 6 (data residency) are the deciding factors for us. Everything else we can read async.</p>', 'Section 4 (architecture) and section 6 (data residency) are the deciding factors for us. Everything else we can read async.', '{}', '<e_0812@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1795754), (CAST(strftime('%s','now') AS INTEGER) - 1795754), '[{"email":"priya.singh@procurement.globex.io","name":"Priya Singh"},{"email":"tariq.khan@legal.acme.co","name":"Tariq Khan"},{"email":"pavel@example.com","name":"Pavel Novak"}]', 'c_eb8f309dcca13e8a'),
  ('e_0813', 'p_g22', 'sales@example.com', 'Re: RFP response — Globex / Acme joint deployment', '<p>From legal: EU-primary with US-failover is acceptable as long as the failover is documented and triggers an in-region notification. GDPR Art. 28(3) compliance is the bar.</p>', 'From legal: EU-primary with US-failover is acceptable as long as the failover is documented and triggers an in-region notification. GDPR Art. 28(3) compliance is the bar.', '{}', '<e_0813@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1692744), (CAST(strftime('%s','now') AS INTEGER) - 1692744), '[{"email":"priya.singh@procurement.globex.io","name":"Priya Singh"},{"email":"olu.adebayo@globex.io","name":"Olu Adebayo"},{"email":"pavel@example.com","name":"Pavel Novak"}]', 'c_eb8f309dcca13e8a'),
  ('e_0814', 'p_g21', 'sales@example.com', 'Re: RFP response — Globex / Acme joint deployment', '<p>Reviewed section 4. The architecture diagram on page 11 has a discrepancy with the description on page 9 — can you clarify whether ingress is single or multi-tenant on the inbound side?</p>', 'Reviewed section 4. The architecture diagram on page 11 has a discrepancy with the description on page 9 — can you clarify whether ingress is single or multi-tenant on the inbound side?', '{}', '<e_0814@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1203230), (CAST(strftime('%s','now') AS INTEGER) - 1203230), '[{"email":"priya.singh@procurement.globex.io","name":"Priya Singh"},{"email":"tariq.khan@legal.acme.co","name":"Tariq Khan"},{"email":"pavel@example.com","name":"Pavel Novak"}]', 'c_eb8f309dcca13e8a'),
  ('e_0815', 'p_g09', 'sales@example.com', 'Re: RFP response — Globex / Acme joint deployment', '<p>We''ve narrowed it to two finalists; you''re one of them. Final pitch slot is next week, Tuesday or Thursday.</p>', 'We''ve narrowed it to two finalists; you''re one of them. Final pitch slot is next week, Tuesday or Thursday.', '{}', '<e_0815@example.test>', 'pass', 'pass', 'pass', 0, (CAST(strftime('%s','now') AS INTEGER) - 674958), (CAST(strftime('%s','now') AS INTEGER) - 674958), '[{"email":"olu.adebayo@globex.io","name":"Olu Adebayo"},{"email":"tariq.khan@legal.acme.co","name":"Tariq Khan"},{"email":"pavel@example.com","name":"Pavel Novak"}]', 'c_eb8f309dcca13e8a'),
  ('e_0816', 'p_g23', 'hello@example.com', 'Co-marketing webinar — joint Q&A format', '<p>Wanted to float a co-marketing idea: a joint webinar between us, Hooli, and you on the topic of ''modern email infrastructure for AI-native teams.'' Soren from Hooli is interested and CC''d.</p>', 'Wanted to float a co-marketing idea: a joint webinar between us, Hooli, and you on the topic of ''modern email infrastructure for AI-native teams.'' Soren from Hooli is interested and CC''d.', '{}', '<e_0816@example.test>', 'pass', 'pass', 'pass', 0, (CAST(strftime('%s','now') AS INTEGER) - 1692199), (CAST(strftime('%s','now') AS INTEGER) - 1692199), '[{"email":"soren.bakke@hooli.com","name":"Soren Bakke"},{"email":"maya@example.com","name":"Maya Iyer"},{"email":"ren@example.com","name":"Ren O''Brien"}]', 'c_6a16bdb30c9e7e1e'),
  ('e_0817', 'p_g24', 'hello@example.com', 'Re: Co-marketing webinar — joint Q&A format', '<p>Hooli''s in if the format is panel + audience Q&A rather than alternating slides. Speakers are easier to recruit for that.</p>', 'Hooli''s in if the format is panel + audience Q&A rather than alternating slides. Speakers are easier to recruit for that.', '{}', '<e_0817@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1639518), (CAST(strftime('%s','now') AS INTEGER) - 1639518), '[{"email":"wren.callahan@piedpiper.ai","name":"Wren Callahan"},{"email":"maya@example.com","name":"Maya Iyer"},{"email":"ren@example.com","name":"Ren O''Brien"}]', 'c_6a16bdb30c9e7e1e'),
  ('e_0818', 'p_g23', 'hello@example.com', 'Re: Co-marketing webinar — joint Q&A format', '<p>Mid-November works. Wren can moderate if that''s helpful — I''ve MC''d two of these for AI conferences and it usually frees the company panelists to be more candid.</p>', 'Mid-November works. Wren can moderate if that''s helpful — I''ve MC''d two of these for AI conferences and it usually frees the company panelists to be more candid.', '{}', '<e_0818@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1524610), (CAST(strftime('%s','now') AS INTEGER) - 1524610), '[{"email":"soren.bakke@hooli.com","name":"Soren Bakke"},{"email":"maya@example.com","name":"Maya Iyer"},{"email":"ren@example.com","name":"Ren O''Brien"}]', 'c_6a16bdb30c9e7e1e'),
  ('e_0819', 'p_g24', 'hello@example.com', 'Re: Co-marketing webinar — joint Q&A format', '<p>Hooli will cover paid promotion in our newsletter (~80k subscribers). Can we get a co-branded landing page or are we sending traffic to a unified one?</p>', 'Hooli will cover paid promotion in our newsletter (~80k subscribers). Can we get a co-branded landing page or are we sending traffic to a unified one?', '{}', '<e_0819@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1324783), (CAST(strftime('%s','now') AS INTEGER) - 1324783), '[{"email":"wren.callahan@piedpiper.ai","name":"Wren Callahan"},{"email":"maya@example.com","name":"Maya Iyer"},{"email":"ren@example.com","name":"Ren O''Brien"}]', 'c_6a16bdb30c9e7e1e'),
  ('e_0820', 'p_g23', 'hello@example.com', 'Re: Co-marketing webinar — joint Q&A format', '<p>Fair. Looking forward to it.</p>', 'Fair. Looking forward to it.', '{}', '<e_0820@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1243633), (CAST(strftime('%s','now') AS INTEGER) - 1243633), '[{"email":"soren.bakke@hooli.com","name":"Soren Bakke"},{"email":"maya@example.com","name":"Maya Iyer"},{"email":"ren@example.com","name":"Ren O''Brien"}]', 'c_6a16bdb30c9e7e1e'),
  ('e_0821', 'p_g00', 'sales@example.com', 'Consolidating three Acme business units onto one tenant', '<p>We''re consolidating Acme, Orbis, and Vandelay (recent acquisitions) onto a single tenant. Each has its own existing email setup — what does a phased migration look like?</p>', 'We''re consolidating Acme, Orbis, and Vandelay (recent acquisitions) onto a single tenant. Each has its own existing email setup — what does a phased migration look like?', '{}', '<e_0821@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 2127186), (CAST(strftime('%s','now') AS INTEGER) - 2127186), '[{"email":"yuki.sato@orbis.health","name":"Yuki Sato"},{"email":"bo.westwood@vandelay.imp","name":"Bo Westwood"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_add97e9de41b6fa3'),
  ('e_0822', 'p_g25', 'sales@example.com', 'Re: Consolidating three Acme business units onto one tenant', '<p>Yuki here from Orbis. Our compliance team needs the read-only archive to be HIPAA-eligible. Does option 2 preserve that?</p>', 'Yuki here from Orbis. Our compliance team needs the read-only archive to be HIPAA-eligible. Does option 2 preserve that?', '{}', '<e_0822@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 2029739), (CAST(strftime('%s','now') AS INTEGER) - 2029739), '[{"email":"elena.varga@acme.co","name":"Elena Varga"},{"email":"bo.westwood@vandelay.imp","name":"Bo Westwood"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_add97e9de41b6fa3'),
  ('e_0823', 'p_g26', 'sales@example.com', 'Re: Consolidating three Acme business units onto one tenant', '<p>Bo from Vandelay. Our setup is small (12 users) so I assume we go last? Our domain is also currently MX''d to a different provider — not sure how that affects sequencing.</p>', 'Bo from Vandelay. Our setup is small (12 users) so I assume we go last? Our domain is also currently MX''d to a different provider — not sure how that affects sequencing.', '{}', '<e_0823@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1884718), (CAST(strftime('%s','now') AS INTEGER) - 1884718), '[{"email":"elena.varga@acme.co","name":"Elena Varga"},{"email":"yuki.sato@orbis.health","name":"Yuki Sato"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_add97e9de41b6fa3'),
  ('e_0824', 'p_g00', 'sales@example.com', 'Re: Consolidating three Acme business units onto one tenant', '<p>Phasing approved internally. Acme first (60 users) starting next month, Orbis 4 weeks later, Vandelay 4 weeks after that.</p>', 'Phasing approved internally. Acme first (60 users) starting next month, Orbis 4 weeks later, Vandelay 4 weeks after that.', '{}', '<e_0824@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1453986), (CAST(strftime('%s','now') AS INTEGER) - 1453986), '[{"email":"yuki.sato@orbis.health","name":"Yuki Sato"},{"email":"bo.westwood@vandelay.imp","name":"Bo Westwood"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_add97e9de41b6fa3'),
  ('e_0825', 'p_g25', 'sales@example.com', 'Re: Consolidating three Acme business units onto one tenant', '<p>Confirmed for the Orbis phase. Will pre-stage our HIPAA addendum so it''s signed before our cutover.</p>', 'Confirmed for the Orbis phase. Will pre-stage our HIPAA addendum so it''s signed before our cutover.', '{}', '<e_0825@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 1077448), (CAST(strftime('%s','now') AS INTEGER) - 1077448), '[{"email":"elena.varga@acme.co","name":"Elena Varga"},{"email":"bo.westwood@vandelay.imp","name":"Bo Westwood"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_add97e9de41b6fa3'),
  ('e_0826', 'p_g26', 'sales@example.com', 'Re: Consolidating three Acme business units onto one tenant', '<p>Vandelay confirmed for the final phase. I''ll loop in our IT once we get within a month of cutover.</p>', 'Vandelay confirmed for the final phase. I''ll loop in our IT once we get within a month of cutover.', '{}', '<e_0826@example.test>', 'pass', 'pass', 'pass', 1, (CAST(strftime('%s','now') AS INTEGER) - 865764), (CAST(strftime('%s','now') AS INTEGER) - 865764), '[{"email":"elena.varga@acme.co","name":"Elena Varga"},{"email":"yuki.sato@orbis.health","name":"Yuki Sato"},{"email":"sam@example.com","name":"Sam Liu"}]', 'c_add97e9de41b6fa3');

INSERT OR REPLACE INTO sent_emails (id, person_id, to_address, from_address, subject, body_html, body_text, in_reply_to, status, sent_at, created_at, cc, conversation_id) VALUES
  ('s_0000', 'p_000', 'tina.kim@hooli.com', 'billing@example.com', 'Re: VAT number for invoice', '<p>Thanks for reaching out — I''ve looped in the right person on our side. Will follow up shortly with a more concrete answer.</p><p>Happy to jump on a call if it''s easier than going back and forth in email.</p><p>For context: we kicked off this initiative back in Q2 and have been iterating since.</p>', 'Thanks for reaching out — I''ve looped in the right person on our side. Will follow up shortly with a more concrete answer.

